vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw*8;
    vec3 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );

    vec2 uv_dz = vUv - vec2(dx.z,dy.z)*0.2;
    vec2 uv_dy = vUv - vec2(dx.y,dy.y)*0.04;
    float emboss = (-dx.y+dy.y) + 1 + (-dx.z + dy.z)*2;

ret = GetPixel(vUv).y*0.2;
ret = mix(vec3(0.2,0,0.1),vec3(0.8,0.6,0),GetPixel(uv_dz).y);
ret *= emboss;
ret = mix(ret,vec3(0.3,0,0.8),GetBlur1(uv_dy).x*1.4);
ret = mix(ret,vec3(1,0.9,0.4),GetPixel(vUv).z*1);


  fragColor = ret;
}
